import React, { useState } from "react";
import { useNavigate } from "react-router-dom";

const AddCategory = () => {
  const navigate = useNavigate();

  const [form, setForm] = useState({
    name: "",
    color: "violet"
  });

  // 🔹 handle input
  const handleChange = (e) => {
    setForm({
      ...form,
      [e.target.name]: e.target.value
    });
  };

  // 🔹 submit
  const handleSubmit = (e) => {
    e.preventDefault();

    if (!form.name.trim()) {
      alert("Category name required ❌");
      return;
    }

    // 🔥 Save in localStorage (frontend)
    const existing =
      JSON.parse(localStorage.getItem("categories")) || [];

    const updated = [...existing, form.name];

    localStorage.setItem("categories", JSON.stringify(updated));

    alert("Category Created ✅");
    navigate(-1);
  };

  return (
    <div className="min-h-screen bg-[#2d3561] text-white flex flex-col items-center p-6">

      {/* 🔙 Back */}
      <div className="w-full max-w-2xl">
        <button
          onClick={() => navigate(-1)}
          className="text-xl mb-4"
        >
          ←
        </button>
      </div>

      <h2 className="text-3xl font-bold mb-6">Add Category</h2>

      <form
        onSubmit={handleSubmit}
        className="w-full max-w-xl space-y-6"
      >

        {/* Category Name */}
        <input
          type="text"
          name="name"
          placeholder="Category name *"
          value={form.name}
          onChange={handleChange}
          required
          className="w-full px-4 py-4 rounded-2xl bg-white/10 border border-white/20 outline-none"
        />

        {/* Color */}
        <select
          name="color"
          value={form.color}
          onChange={handleChange}
          className="w-full px-4 py-4 rounded-2xl bg-white/10 border border-white/20 outline-none"
        >
          <option className="text-black">violet</option>
          <option className="text-black">blue</option>
          <option className="text-black">green</option>
          <option className="text-black">red</option>
          <option className="text-black">yellow</option>
        </select>

        {/* Button */}
        <button
          type="submit"
          className="w-full py-4 rounded-full bg-gradient-to-r from-purple-500 to-pink-500 text-white text-xl font-semibold hover:scale-105 transition"
        >
          Create Category
        </button>

      </form>
    </div>
  );
};

export default AddCategory;
